    graduados: ['graduado', 'egresado', 'alumni', 'título', 'diploma', 'profesional', 'colegio', 'matricula']
  };
  
  for (const [category, words] of Object.entries(keywords)) {
    if (words.some(word => text.includes(word))) {
      return category;
    }
  }
  
